// 2.8.3 HF306 | 2023-10-13 |raj |  DFCT0012229 - Address GlideRecordSecure Issues in the Event swap Performance Fix
// 2.8.3HF | 2023-09-24 | DFCT0012179 -	DIA - Tasks not getting created when using "Select to Create Subtasks for Each OU" with 30 OUs or more under the primary assignee
// Script Continued Below

// DFCT0012229 - this is called only from an event where the admin many not have the needed permissions.
//               getting a new reference to the record as glide record, not glide record secure 
//               this is to ensure processing of this record can be performaed without acls
var gr_task = new GlideRecord("x_153465_discovert_route_task_instance");

if(gr_task.get(current.getUniqueValue())){
	new Task_uiAction().uiAction_CreateSubtasksforEachSubOUs(gr_task);
} else {
	gs.error("Tasker - DiscoverTasker_CreateOUSubtasks - error loading the task passed to the event");
}
